class Solution:
    def countCharacters(self, words: List[str], chars: str) -> int:
        char_count = {}
        for char in chars:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1
        good_strings = 0
        for word in words:
            word_count = {}
            for char in word:
                if char in word_count:
                    word_count[char] += 1
                else:
                    word_count[char] = 1
            is_good = True
            for char, count in word_count.items():
                if char not in char_count or count > char_count[char]:
                    is_good = False
                    break
            if is_good:
                good_strings += len(word)
        return good_strings
```
